using namespace std;

struct UnionFind {
    int N;
    vector<int> par, siz;

    int find(int x) { return (par[x] == x ? x : par[x] = find(par[x])); }

    void merge(int x, int y) {
        x = find(x), y = find(y);
        if (x == y) return;
        if (siz[x] > siz[y]) swap(x, y);
        par[x] = y;
        siz[y] += siz[x];
    }

    UnionFind(int N) : N(N), siz(N, 1), par(N) {
        iota(par.begin(), par.end(), 0);
    }
};

// 方向を表す
int dx[] = {-1, 0, 1, 0}, dy[] = {0, 1, 0, -1};

// 操作
struct Act {
    int type, x, y;
};

struct Game {
    vector<vector<bool>> C;
    vector<vector<bool>> wall_hrz, wall_vert;
    vector<int> X, Y, wall_used, score;
    bool is_finished = false;

    int MAX_WALL = 10;
    int turn = 0;
    vector<Act> acts;

    // 連結性が保たれているかの判定
    bool isConnected() {
        UnionFind uf(81);
        rep(i, 9) rep(j, 9) {
                if (i < 8 && !wall_hrz[i][j]) uf.merge(i * 9 + j, (i + 1) * 9 + j);
                if (j < 8 && !wall_vert[i][j]) uf.merge(i * 9 + j, i * 9 + j + 1);
            }
        return uf.siz[uf.find(0)] == 81;
    }

    // 操作が適正であるかの判定
    bool isOK(Act act) {
        if (act.type == 0) {
            if (act.x == 0)  // 上
                return X[turn] && !wall_hrz[X[turn] - 1][Y[turn]];
            else if (act.x == 1)  // 右
                return Y[turn] != 8 && !wall_vert[X[turn]][Y[turn]];
            else if (act.x == 2)  // 下
                return X[turn] != 8 && !wall_hrz[X[turn]][Y[turn]];
            else if (act.x == 3)  // 左
                return Y[turn] && !wall_vert[X[turn]][Y[turn] - 1];
            else
                return false;
        } else if (act.type == 1) {
            if (act.x < 0 || act.x > 7 || act.y < 0 || act.y > 7) return false;
            if (wall_used[turn] == MAX_WALL)
                return false;  // 11 回目に置こうとしたらアウト
            if (wall_hrz[act.x][act.y] ||
                wall_hrz[act.x][act.y + 1])  // 既に置かれていたらアウト
                return false;
            wall_hrz[act.x][act.y] = wall_hrz[act.x][act.y + 1] = true;
            bool res = isConnected();  // 連結性チェック
            wall_hrz[act.x][act.y] = wall_hrz[act.x][act.y + 1] = false;
            return res;
        } else if (act.type == 2) {
            if (act.x < 0 || act.x > 7 || act.y < 0 || act.y > 7) return false;
            if (wall_used[turn] == MAX_WALL) return false;
            if (wall_vert[act.x][act.y] || wall_vert[act.x + 1][act.y])
                return false;
            wall_vert[act.x][act.y] = wall_vert[act.x + 1][act.y] = true;
            bool res = isConnected();
            wall_vert[act.x][act.y] = wall_vert[act.x + 1][act.y] = false;
            return res;
        } else
            return false;
    }

    // 操作の候補
    vector<Act> candidateActs(bool no_wall = false) {
        vector<Act> res;
        rep(i, 4) {
            if (isOK(Act{0, i, 0}))
                res.push_back(Act{0, i, 0});  // 隣接マスへ移動
        }
        rep(i, 9) rep(j, 9) {
                bool flag_i = i <= X[turn] && X[turn] <= i + 1 && j <= Y[turn] && Y[turn] <= j + 1;
                bool flag_j = i <= X[turn ^ 1] && X[turn ^ 1] <= i + 1 && j <= Y[turn ^ 1] && Y[turn ^ 1] <= j + 1;
                if (!(flag_j) || no_wall) continue;
                if (isOK(Act{1, i, j}))
                    res.push_back(Act{1, i, j});  // 水平方向の壁
                if (isOK(Act{2, i, j}))
                    res.push_back(Act{2, i, j});  // 垂直方向の壁
            }
        return res;
    }

    // 操作を実行する
    bool applyAct(Act act, bool check = true) {
        if (check && !isOK(act)) return false;
        if (act.type == 0) {  // 隣接マスへ移動
            X[turn] += dx[act.x];
            Y[turn] += dy[act.x];
            if (C[X[turn]][Y[turn]]) {
                score[turn]++;
                C[X[turn]][Y[turn]] = false;
            }
        } else if (act.type == 1) {  // 水平方向の壁
            wall_hrz[act.x][act.y] = wall_hrz[act.x][act.y + 1] = true;
            wall_used[turn]++;
        } else {  // 垂直方向の壁
            wall_vert[act.x][act.y] = wall_vert[act.x + 1][act.y] = true;
            wall_used[turn]++;
        }
        // ゲームが終了しているかの判定
        bool flag = false;
        rep(i, 9) rep(j, 9) {
                if (C[i][j]) flag = true;
            }
        if (!flag) is_finished = true;
        acts.push_back(act);

        // 交代
        turn ^= 1;
        return true;
    }

    // スコアや盤面を出力する（デバッグ用）
    void printBoard() {
        cerr << "Score: " << score[0] << " " << score[1] << "\n"
             << "Wall counter: " << wall_used[0] << " " << wall_used[1] << endl
             << endl;
        rep(i, 9) {
            rep(j, 9) {
                if (i == X[0] && j == Y[0] && i == X[1] && j == Y[1])
                    cerr << " AB";
                else if (i == X[0] && j == Y[0])
                    cerr << " A ";
                else if (i == X[1] && j == Y[1])
                    cerr << " B ";
                else {
                    if (C[i][j])
                        cerr << " # ";
                    else
                        cerr << " . ";
                }
                if (j < 8) cerr << (wall_vert[i][j] ? " | " : "   ");
            }
            cerr << endl;
            if (i != 8) {
                rep(j, 9) {
                    if (j) cerr << "   ";
                    cerr << (wall_hrz[i][j] ? "---" : "   ");
                }
            }
            cerr << endl;
        }
        cerr << endl;
    }

    Game()
            : C(9, vector<bool>(9)),
              wall_hrz(9, vector<bool>(9)),
              wall_vert(9, vector<bool>(9)),
              X(2),
              Y(2),
              wall_used(2),
              score(2) {
        wall_used[0] = wall_used[1] = 0;
        score[0] = score[1] = 0;
        X[0] = 8, X[1] = 0, Y[0] = Y[1] = 4;
    }

    int get_score(int t) {
//        return score[t] - score[t ^ 1];
        if (score[t] > score[t ^ 1]) return 1;
        else if (score[t] == score[t ^ 1]) return 0;
        else return -1;
    }
};

int play_out(Game game) {

    int t = game.turn;
    while (!game.is_finished) {
        auto acts = game.candidateActs();
        std::uniform_int_distribution<int> dist(0, (int) acts.size());
        int i = dist(mt);
        game.applyAct(acts[i]);
    }
    return game.get_score(t);
}

struct Node {
    Game state;
    int n;
    int w;
    vector<Node *> child;

    Node(Game state) : state(state) {
        n = 0;
        w = 0;
        child = vector<Node *>(0);
    }

    void expand() {
        for (auto act: state.candidateActs()) {
            auto st_copy = state;
            st_copy.applyAct(act);
            child.emplace_back(new Node(st_copy));
        }
    }

    int evaluate() {
        if (state.is_finished) {
            int v = state.get_score(state.turn);
            w += v;
            n += 1;
            return v;
        }

        if (child.empty()) {
            int v = play_out(state);
            w += v;
            n += 1;
            if (n == expand_num) expand();
            return v;
        } else {
            int v = -next_child()->evaluate();
            w += v;
            n += 1;
            return v;
        }
    }

    Node *next_child() {
        int t = 0;
        for (auto ch: child) {
            if (ch->n == 0) return ch;
            t += ch->n;
        }

        vector<double> uct;
        for (auto ch: child) {
            double p = (double) -ch->w / (double) ch->n + sqrt(2.0 * log((double) t) / (double) ch->n);
            uct.emplace_back(p);
        }

        int ind = 0;
        double mx = -1e10;
        for (int i = 0; i < uct.size(); i++) {
            if (mx < uct[i])ind = i, mx = uct[i];
        }

        return child[ind];
    }
};

// 処理に掛かっている合計時間
double tim_sum;

// 自分のターンになったら呼ばれるので、操作を選ぶ。先手なら game.turn=0,
// 後手なら game.turn=1 の状態で呼ばれる
Act choose(Game game) {
    // 時間計測用
    chrono::system_clock::time_point clk = chrono::system_clock::now();

    Node root = Node(game);
    root.expand();
//    for (int qi = 0; qi < int(evaluate_num); qi++) root.evaluate();
    while (static_cast<double>(chrono::duration_cast<chrono::microseconds>(
            chrono::system_clock::now() - clk)
                                       .count() /
                               1000000.0) < 0.9)
        root.evaluate();
    auto acts = game.candidateActs();
    vector<int> n_list;
    for (auto ch: root.child) n_list.emplace_back(ch->n);

    int ind = 0;
    int mx = -1001001001;
    for (int i = 0; i < int(n_list.size()); i++)
        if (mx < n_list[i]) ind = i, mx = n_list[i];

    for (auto ni: n_list) cerr << ni << ' ';
    cerr << endl;

    Act best_act = acts[ind];
    return best_act;
}

